// Parse intake form email
const email = $input.first().json;
const body = email.textPlain || email.textHtml || '';

// Extract key fields (simplified - real implementation would parse structured data)
const nameMatch = body.match(/Name[:\s]+([^\n]+)/);
const emailMatch = body.match(/Email[:\s]+([^\n@]+@[^\n@]+)/);
const matterMatch = body.match(/Legal Issue[:\s]+([^\n]+)/);
const urgencyMatch = body.match(/Urgency[:\s]+([^\n]+)/);

const clientName = nameMatch ? nameMatch[1].trim() : 'Unknown Client';
const clientEmail = emailMatch ? emailMatch[1].trim() : 'unknown@example.com';
const matterType = matterMatch ? matterMatch[1].trim() : 'General';
const urgency = urgencyMatch ? urgencyMatch[1].trim().toLowerCase() : 'normal';

// Categorize matter type
let category = 'general';
if (matterType.toLowerCase().includes('family') || matterType.toLowerCase().includes('divorce')) {
  category = 'family_law';
} else if (matterType.toLowerCase().includes('business') || matterType.toLowerCase().includes('contract')) {
  category = 'business_law';
} else if (matterType.toLowerCase().includes('estate') || matterType.toLowerCase().includes('will')) {
  category = 'estate_planning';
} else if (matterType.toLowerCase().includes('injury') || matterType.toLowerCase().includes('accident')) {
  category = 'personal_injury';
}

return [{
  json: {
    clientName: clientName,
    clientEmail: clientEmail,
    matterType: matterType,
    category: category,
    urgency: urgency,
    receivedAt: new Date().toISOString(),
    emailBody: body
  }
}];

