// Create intake file for CRM/practice management
const data = $input.first().json;
const fs = require('fs');

const fileName = `intake_${data.clientName.replace(/\s+/g, '_')}_${Date.now()}.md`;
const filePath = `/home/user/LegalNotes/Intakes/${fileName}`;

const fileContent = `---
client_name: ${data.clientName}
client_email: ${data.clientEmail}
matter_type: ${data.matterType}
category: ${data.category}
urgency: ${data.urgency}
received_at: ${data.receivedAt}
status: new
---

# Client Intake - ${data.clientName}

**Received**: ${data.receivedAt}
**Category**: ${data.category}
**Urgency**: ${data.urgency}

## Client Information
- **Name**: ${data.clientName}
- **Email**: ${data.clientEmail}

## Matter Details
${data.matterType}

## Next Steps
- [ ] Attorney review
- [ ] Schedule initial consultation
- [ ] Conflicts check
- [ ] Engagement letter

## Original Submission
${data.emailBody}
`;

fs.writeFileSync(filePath, fileContent);

return [{ json: { fileName: fileName, filePath: filePath } }];
